mapper.select:
SELECT A.WIRE_PROD_DTL_SEQ, A.WIRE_PROD_CD, A.WIRE_PROD_CORP, A.WIRE_PROD_NAME, A.WIRE_PROD_STICKER, A.WIRE_PROD_AMT, A.WIRE_PROD_AMT_DESC, A.WIRE_PROD_AMT_TEXT, A.WIRE_PROD_AMT_TYPE, A.WIRE_PROD_RECOM_YN, A.WIRE_PROD_IMG, A.WIRE_PROD_IMG_DESC, A.WIRE_PROD_TEXT, A.WIRE_PROD_CHANNEL, A.WIRE_PROD_SPEED, A.WIRE_PROD_FREEBIES FROM NMCP_WIRE_PROD_DTL A, NMCP_CD_DTL B WHERE 1=1 AND B.CD_GROUP_ID = 'WIREPRODCORP' AND B.DTL_CD = A.WIRE_PROD_CORP AND B.USE_YN = 'Y' AND A.WIRE_PROD_SHOW_YN = 'Y'
AND A.WIRE_PROD_CD IN ('TV01','IT01')
AND A.WIRE_PROD_CD = #{wireProdCd}
AND A.WIRE_PROD_CORP = #{wireProdCorp}
AND A.WIRE_PROD_CD <> 'AD01'
ORDER BY DECODE(A.WIRE_PROD_CD, 'CB01',1 ,'IT01',2 ,'TV01',3), A.WIRE_PROD_RECOM_YN, A.WIRE_PROD_REG_DT DESC
